//https://docs.microsoft.com/azure/azure-monitor/platform/monitor-workspace
_LogOperation 
| summarize count() by Level

//Usage
//| where StartTime {TimeRange:value}
//| summarize ['Table Size'] =sum(Quantity)/1000 by ['Table Name'] =DataType,['IsBillable'] =IsBillable
//| order by ['Table Size']  desc
 
let list_ = 
externaldata (
    Table:string, solution_Name:string, solution_Folder:string, solution_publisher_id:string, solution_offer_id:string,
    solution_first_publish_date:datetime, solution_last_publish_date:datetime, solution_version:string,
    solution_support_name:string, solution_support_tier:string, solution_support_link:string,
    solution_author_name:string, solution_categories:string, connector_id:string, connector_publisher:string,
    connector_title:string, connector_description:string, connector_instruction_steps:string, connector_permissions:string, connector_files:string, is_unique:bool
)
[
 @"https://raw.githubusercontent.com/Azure/Azure-Sentinel/refs/heads/master/Tools/Solutions%20Analyzer/solutions_connectors_tables_mapping.csv"
]
with (format="csv", ignoreFirstRecord=true);
// Pre-aggregate mapping per table
let mapping =
list_
| summarize
    solution_Names = array_sort_asc(make_set(solution_Name)),
    connector_ids  = array_sort_asc(make_set(connector_id)), connector_description=any(connector_description), solution_support_link=any(solution_support_link)
  by Table
| extend solution_Names = trim(@"[^\w]+",tostring(solution_Names))
| extend solution_Names = replace(@"""", " ", tostring(solution_Names))
| extend connector_ids = trim(@"[^\w]+",tostring(connector_ids))
| extend connector_ids = replace(@"""", " ", tostring(connector_ids))
;
// Main query: table size + enrichment
Usage
| summarize ['Table Size'] = sum(Quantity) / 1000
    by ['Table Name'] = DataType, ['IsBillable'] = IsBillable
| join kind=leftouter mapping
    on $left.['Table Name'] == $right.Table
| extend solution_Names = iif(isempty(solution_Names) and ['Table Name'] endswith '_CL',"Custom Log",solution_Names) 
//| extend solution_Names = iif(isempty(solution_Names) and ['Table Name'] startswith 'Device',"Microsoft Defender",solution_Names) 
| project
    ['Table Name'],
    ['Table Size'],
    ['IsBillable'],
    solution_Names,
    connector_ids, connector_description
| order by ['Table Size'] desc

//Usage
//| where StartTime {TimeRange:value}
//| summarize ['Table Size'] =sum(Quantity)/1000 by ['Table Name'] =DataType,['IsBillable'] =IsBillable
//| order by ['Table Size']  desc
 
let list_ = 
externaldata (
    Table:string, solution_Name:string, solution_Folder:string, solution_publisher_id:string, solution_offer_id:string,
    solution_first_publish_date:datetime, solution_last_publish_date:datetime, solution_version:string,
    solution_support_name:string, solution_support_tier:string, solution_support_link:string,
    solution_author_name:string, solution_categories:string, connector_id:string, connector_publisher:string,
    connector_title:string, connector_description:string, connector_instruction_steps:string, connector_permissions:string, connector_files:string, is_unique:bool
)
[
 @"https://raw.githubusercontent.com/Azure/Azure-Sentinel/refs/heads/master/Tools/Solutions%20Analyzer/solutions_connectors_tables_mapping.csv"
]
with (format="csv", ignoreFirstRecord=true);
// Pre-aggregate mapping per table
let mapping =
list_
| summarize
    solution_Names = array_sort_asc(make_set(solution_Name)),
    connector_ids  = array_sort_asc(make_set(connector_id)), connector_description=any(connector_description), solution_support_link=any(solution_support_link)
  by Table
| extend solution_Names = trim(@"[^\w]+",tostring(solution_Names))
| extend solution_Names = replace(@"""", " ", tostring(solution_Names))
| extend connector_ids = trim(@"[^\w]+",tostring(connector_ids))
| extend connector_ids = replace(@"""", " ", tostring(connector_ids))
;
// Main query: table size + enrichment
Usage
| summarize ['Table Size'] = sum(Quantity) / 1000
    by ['Table Name'] = DataType, ['IsBillable'] = IsBillable
| join kind=leftouter mapping
    on $left.['Table Name'] == $right.Table
| extend solution_Names = iif(isempty(solution_Names) and ['Table Name'] endswith '_CL',"Custom Log",solution_Names) 
//| extend solution_Names = iif(isempty(solution_Names) and ['Table Name'] startswith 'Device',"Microsoft Defender",solution_Names) 
| project
    ['Table Name'],
    ['Table Size'],
    ['IsBillable'],
    solution_Names,
    connector_ids, connector_description
| order by ['Table Size'] desc

//find where TimeGenerated {TimeRange:query} project _BilledSize, _IsBillable, Computer, DataType, TimeGenerated
Usage
| where StartTime {TimeRange:value}
| make-series Trend=sum(Quantity)/1000 , count() on TimeGenerated from {TimeRange:start} to {TimeRange:end} step {TimeRange:grain} 
| extend (anomalies, score, baseline) = series_decompose_anomalies(Trend, 1.5, 7, 'linefit', 1, 'ctukey', 0.01)
| project baseline, Trend //, count_

find where TimeGenerated {TimeRange:query} project _BilledSize, _IsBillable, Computer, DataType, TimeGenerated
| where '{Table}' == 'All Tables' or DataType == '{Table}'
| make-series TableSize = count() default = 0 on TimeGenerated from {TimeRange:start} to {TimeRange:end} step {TimeRange:grain}
//| mv-expand TableSize to typeof(real), TimeGenerated to typeof(datetime) limit 1000
| project TimeGenerated, ['{Table}'] = TableSize

Usage
| make-series TableSize = sum(Quantity) default = 0 on TimeGenerated from {TimeRange:start} to {TimeRange:end} step {TimeRange:grain} 
//| mv-expand TableSize to typeof(real), TimeGenerated to typeof(datetime) limit 1000
| project TimeGenerated, ['{Table}'] = TableSize

let timerange=30d;
AuditLogs
// extend LocalTime to your time zone
| extend LocalTime=TimeGenerated + 5h
| where LocalTime > ago(timerange)
// Change hours of the day to suit your company, i.e this would find activations between 6pm and 6am
| where hourofday(LocalTime) !between (6 .. 18)
| where OperationName == "Add member to role completed (PIM activation)"
| extend RoleName = tostring(TargetResources[0].displayName)
| project LocalTime, OperationName, Identity, RoleName, ActivationReason=ResultReason,  WorkspaceID=TenantId

//Detect when a user denies MFA several times within a single sign in attempt and then completes MFA.
//This could be a sign of someone trying to spam your users with MFA prompts until they accept.

//Data connector required for this query - Azure Active Directory - Signin Logs

//Select your threshold of how many times a user denies MFA before accepting
let threshold=2;
SigninLogs
| project
    TimeGenerated,
    AuthenticationRequirement,
    AuthenticationDetails,
    UserPrincipalName,
    CorrelationId
//Include only authentications that require MFA
| where AuthenticationRequirement == "multiFactorAuthentication"
//Extend authentication result description
| extend AuthResult = tostring(parse_json(AuthenticationDetails)[1].authenticationStepResultDetail)
//Find results that include both denined and completed MFA
| where AuthResult in ("MFA completed in Azure AD", "MFA denied; user declined the authentication","MFA denied; user did not respond to mobile app notification")
//Create a list of completed and denied MFA challenges per correlation id
| summarize ['Result Types']=make_list(AuthResult) by CorrelationId, UserPrincipalName
//Ensure the list includes both completed and denied MFA challenges
| where ['Result Types'] has ("MFA completed in Azure AD") and ['Result Types'] has_any ("MFA denied; user declined the authentication", "MFA denied; user did not respond to mobile app notification")
| mv-expand ['Result Types'] to typeof(string)
//Expand and count all the denied challenges and then return CorrelationId's where the MFA denied count is greater or equal to your threshold
| where ['Result Types'] has_any ("MFA denied; user declined the authentication","MFA denied; user did not respond to mobile app notification")
| summarize ['Denied MFA Count']=count()by ['Result Types'], CorrelationId, UserPrincipalName
| where ['Denied MFA Count'] >= threshold

//Detects when a user registers MFA details on their account and then completes self service password reset with a short timeframe

//Data connector required for this query - Azure Active Directory - Signin Logs
//Data connector required for this query - Azure Active Directory - Audit Logs

let timeframe=4h;
AuditLogs
//| where TimeGenerated > ago(1d)
| where OperationName in ("User changed default security info", "User registered all required security info", "User registered security info")
| extend User = tostring(TargetResources[0].userPrincipalName)
| project SecurityInfoTime=TimeGenerated, User, OperationName
| join kind=inner (
    AuditLogs
    //| where TimeGenerated > ago(1d)
    | where OperationName in ("Reset password (self-service)", "Change password (self-service)")
    | where Result == "success"
    | extend User = tostring(TargetResources[0].userPrincipalName)
    | project PasswordResetTime=TimeGenerated, OperationName, User)
    on User
| where (PasswordResetTime - SecurityInfoTime) between (0min .. timeframe)
| project-away User1

//Detect when MFA details for a user are changed, deleted or registered from an IP address that user has never signed in successfully from

//Data connector required for this query - Azure Active Directory - Signin Logs
//Data connector required for this query - Azure Active Directory - Audit Logs

//Cache all successful sign in data for users using materialize operator
let signindata=materialize (
    SigninLogs
    | where TimeGenerated > ago(180d)
    | where ResultType == 0
    | distinct UserPrincipalName, UserId, IPAddress);
//Search for audit events showing MFA registrations, deletions or changes in the last day
AuditLogs
| where TimeGenerated > ago(10d)
| where OperationName in ("User registered security info", "User deleted security info", "User registered all required security info")
| where Result == "success"
| extend IPAddress = tostring(parse_json(tostring(InitiatedBy.user)).ipAddress)
| extend UserPrincipalName = tostring(parse_json(tostring(InitiatedBy.user)).userPrincipalName)
| extend UserId = tostring(TargetResources[0].id)
| project UserPrincipalName, UserId, IPAddress, OperationName
//Join those events back to our summarized sign in data looking for users who register MFA from an IP they have never signed in from
| where isnotempty(IPAddress)
| join kind=leftanti (signindata) on IPAddress, UserId
| distinct UserPrincipalName, IPAddress, OperationName

//Who are all my guest accounts in the tenant?
IdentityInfo
| where UserType == "Guest"
//| summarize dcount(AccountObjectId) by AccountUPN, bin(TimeGenerated,{TimeRange:grain})
| make-series dcount(AccountObjectId) default=0 on TimeGenerated from {TimeRange:start} to {TimeRange:end} step {TimeRange:grain} by AccountUPN

// ---------------------------------------------
// 0) Workbook parameters
// ---------------------------------------------
let StartTime = todatetime({TimeRange:start});
let EndTime   = todatetime({TimeRange:end});

// SLA parameters entered in HOURS; convert to MINUTES with defaults
let SLA_High_Min   = iff(isempty(trim(" ", "{slaHigh}")),   60.0,   toreal("{slaHigh}")   * 60.0);
let SLA_Medium_Min = iff(isempty(trim(" ", "{slaMedium}")), 480.0,  toreal("{slaMedium}") * 60.0);
let SLA_Low_Min    = iff(isempty(trim(" ", "{slaLow}")),    1440.0, toreal("{slaLow}")    * 60.0);
let SLA_Info_Min   = iff(isempty(trim(" ", "{slaInfo}")),   real(null), toreal("{slaInfo}") * 60.0);

// ---------------------------------------------
// 1) Build per-incident dataset (latest record)
// ---------------------------------------------
let Incidents =
    SecurityIncident
    | where isnotempty(IncidentNumber)
    | where TimeGenerated between (StartTime .. EndTime)
    | summarize arg_max(LastModifiedTime, *) by IncidentNumber
    | extend
        // MTTT / MTTH: Created -> FirstModified
        TTT_hours = iff(isnotnull(CreatedTime) and isnotnull(FirstModifiedTime),
                        datetime_diff("minute", FirstModifiedTime, CreatedTime) / 60.0,
                        real(null)),

        // MTTC: Created -> Closed
        TTC_hours = iff(isnotnull(CreatedTime) and isnotnull(ClosedTime),
                        datetime_diff("minute", ClosedTime, CreatedTime) / 60.0,
                        real(null)),

        // MTTD: FirstActivity -> Created
        TTD_hours = iff(isnotnull(FirstActivityTime) and isnotnull(CreatedTime),
                        datetime_diff("minute", CreatedTime, FirstActivityTime) / 60.0,
                        real(null)),

        // Internal: MTTC in minutes (for SLA comparison)
        TTC_Minutes = iff(isnotnull(CreatedTime) and isnotnull(ClosedTime),
                          todouble(datetime_diff("minute", ClosedTime, CreatedTime)),
                          real(null)),

        // Internal: SLA target (minutes) per severity
        SLA_Target_Minutes = case(
            Severity == "High", SLA_High_Min,
            Severity == "Medium", SLA_Medium_Min,
            Severity == "Low", SLA_Low_Min,
            Severity == "Informational", SLA_Info_Min,
            real(null)
        )
    | extend
        // Only evaluate SLA for closed incidents with a configured SLA target
        HasSLA = iff(isnotnull(TTC_Minutes) and isnotnull(SLA_Target_Minutes), 1, 0),
        SLA_Within = iff(isnotnull(TTC_Minutes) and isnotnull(SLA_Target_Minutes) and TTC_Minutes <= SLA_Target_Minutes, 1, 0),
        SLA_Breached = iff(isnotnull(TTC_Minutes) and isnotnull(SLA_Target_Minutes) and TTC_Minutes > SLA_Target_Minutes, 1, 0);

// ---------------------------------------------
// 2) Break down metrics by Severity
// ---------------------------------------------
Incidents
| summarize
    TotalIncidents = dcount(IncidentNumber),
    MTTT_P50_hours = percentile(TTT_hours, 50),
    MTTC_P50_hours = percentile(TTC_hours, 50),
    MTTD_P50_hours = percentile(TTD_hours, 50),
    MTTC_P90_hours = percentile(TTC_hours, 90),

    // SLA rollups per severity
    SLA_Target_Minutes = any(SLA_Target_Minutes),
    ['Within SLA'] = sum(SLA_Within),
    ['SLA breach'] = sum(SLA_Breached),
    SLA_Evaluated = sum(HasSLA)
  by Severity
| extend
    ['SLA attainment %'] =
        iff(SLA_Evaluated == 0, real(null), round(100.0 * todouble(['Within SLA']) / todouble(SLA_Evaluated), 2))

// ---------------------------------------------
// 3) Add severity ranking + emoji labels
// ---------------------------------------------
| extend
    SeverityRank = case(
        Severity == "High", 1,
        Severity == "Medium", 2,
        Severity == "Low", 3,
        Severity == "Informational", 4,
        99
    ),
    SeverityLabel = case(
        Severity == "High", "High 🔴",
        Severity == "Medium", "Medium 🟡",
        Severity == "Low", "Low 🟢",
        Severity == "Informational", "Informational",
        Severity
    )

// ---------------------------------------------
// 4) Sort using numeric rank
// ---------------------------------------------
| sort by SeverityRank asc

// ---------------------------------------------
// 5) Final projection (keep existing column names)
// ---------------------------------------------
| project
    Severity = SeverityLabel,
    TotalIncidents,
    ['MTTT/H (hours)'] = round(MTTT_P50_hours, 2),
    ['MTTC (hours)'] = round(MTTC_P50_hours, 2),
    ['MTTD (hours)'] = round(MTTD_P50_hours, 2),
    ['MTTC, worst 10% (hours)'] = round(MTTC_P90_hours, 2),
// SLA
    
    ['Within SLA'],
    ['SLA breach'],
    ['SLA attainment %'],
    ['SLA value (hours)'] = iff(isnull(SLA_Target_Minutes), real(null), round(SLA_Target_Minutes / 60.0, 2))

// ---------------------------------------------
// 0) Workbook parameters
// ---------------------------------------------
let StartTime = todatetime({TimeRange:start});
let EndTime   = todatetime({TimeRange:end});
let SelectSLA = "{selectSLA}";

// SLA parameters entered in HOURS; convert to MINUTES with defaults
let SLA_High_Min   = iff(isempty(trim(" ", "{slaHigh}")),   60.0,   toreal("{slaHigh}")   * 60.0);
let SLA_Medium_Min = iff(isempty(trim(" ", "{slaMedium}")), 480.0,  toreal("{slaMedium}") * 60.0);
let SLA_Low_Min    = iff(isempty(trim(" ", "{slaLow}")),    1440.0, toreal("{slaLow}")    * 60.0);
let SLA_Info_Min   = iff(isempty(trim(" ", "{slaInfo}")),   real(null), toreal("{slaInfo}") * 60.0);

// ---------------------------------------------
// 1) Build per-incident dataset (latest record)
// ---------------------------------------------
let Incidents =
    SecurityIncident
    | where isnotempty(IncidentNumber)
    | where TimeGenerated between (StartTime .. EndTime)
    | summarize arg_max(LastModifiedTime, *) by IncidentNumber
    | extend
        // MTTT / MTTH: Created -> FirstModified
        TTT_hours = iff(isnotnull(CreatedTime) and isnotnull(FirstModifiedTime),
                        datetime_diff("minute", FirstModifiedTime, CreatedTime) / 60.0,
                        real(null)),

        // MTTC: Created -> Closed
        TTC_hours = iff(isnotnull(CreatedTime) and isnotnull(ClosedTime),
                        datetime_diff("minute", ClosedTime, CreatedTime) / 60.0,
                        real(null)),

        // MTTD: FirstActivity -> Created
        TTD_hours = iff(isnotnull(FirstActivityTime) and isnotnull(CreatedTime),
                        datetime_diff("minute", CreatedTime, FirstActivityTime) / 60.0,
                        real(null)),

        // Internal: MTTC in minutes (for SLA comparison)
        TTC_Minutes = iff(isnotnull(CreatedTime) and isnotnull(ClosedTime),
                          todouble(datetime_diff("minute", ClosedTime, CreatedTime)),
                          real(null)),

        // Internal: SLA target (minutes) per severity
        SLA_Target_Minutes = case(
            Severity == "High", SLA_High_Min,
            Severity == "Medium", SLA_Medium_Min,
            Severity == "Low", SLA_Low_Min,
            Severity == "Informational", SLA_Info_Min,
            real(null)
        )
    | extend
        HasSLA = iff(isnotnull(TTC_Minutes) and isnotnull(SLA_Target_Minutes), 1, 0),
        SLA_Within = iff(isnotnull(TTC_Minutes) and isnotnull(SLA_Target_Minutes) and TTC_Minutes <= SLA_Target_Minutes, 1, 0),
        SLA_Breached = iff(isnotnull(TTC_Minutes) and isnotnull(SLA_Target_Minutes) and TTC_Minutes > SLA_Target_Minutes, 1, 0);

// ---------------------------------------------
// 2) Calculate worst 10% MTTC threshold
// ---------------------------------------------
let MTTCWorstThreshold =
    toscalar(
        Incidents
        | where isnotnull(TTC_hours)
        | summarize percentile(TTC_hours, 90)
    );

// ---------------------------------------------
// 3) Return incident list based on selectSLA
// ---------------------------------------------
Incidents
| where
    case(
        SelectSLA == "MTTCworst", isnotnull(TTC_hours) and TTC_hours >= MTTCWorstThreshold,
        SelectSLA == "withinSLA", SLA_Within == 1,
        SelectSLA == "SLAbreach", SLA_Breached == 1,
        true
    )
| extend
    SeverityRank = case(
        Severity == "High", 1,
        Severity == "Medium", 2,
        Severity == "Low", 3,
        Severity == "Informational", 4,
        99
    ),
    SeverityLabel = case(
        Severity == "High", "High 🔴",
        Severity == "Medium", "Medium 🟡",
        Severity == "Low", "Low 🟢",
        Severity == "Informational", "Informational",
        Severity
    )
| sort by SeverityRank asc, TTC_hours desc
| project
    IncidentNumber,
    Title,
    Severity = SeverityLabel,
    Status,
    Owner,
    CreatedTime,
    ClosedTime,
    ['MTTT/H (hours)'] = round(TTT_hours, 2),
    ['MTTC (hours)'] = round(TTC_hours, 2),
    ['MTTD (hours)'] = round(TTD_hours, 2),
    //['MTTC, worst 10% threshold (hours)'] = round(MTTCWorstThreshold, 2),
    ['Within SLA'] = iff(SLA_Within == 1, "Yes", "No"),
    ['SLA breach'] = iff(SLA_Breached == 1, "Yes", "No"),
    ['SLA value (hours)'] = iff(isnull(SLA_Target_Minutes), real(null), round(SLA_Target_Minutes / 60.0, 2))

// ---------------------------------------------
// Counts by Severity over time (CreatedTime)
// ---------------------------------------------

let BinSize  = 1d;

SecurityIncident
//| summarize arg_max(LastModifiedTime, *) by IncidentNumber
| summarize
    //TotalIncidents = dcount(IncidentNumber),
    ["High 🔴"]   = countif(Severity == "High"),
    ["Medium 🟡"] = countif(Severity == "Medium"),
    ["Low 🟢"]    = countif(Severity == "Low"),
    Informational = countif(Severity == "Informational")
  by TimeBucket = bin(TimeGenerated, BinSize)
| sort by TimeBucket asc

// ---------------------------------------------
// Median MTTx (P50) + MTTC P90 over time
// ---------------------------------------------
let Lookback = 30d;
let BinSize  = 1d;

SecurityIncident
//| where CreatedTime >= ago(Lookback)
| summarize arg_max(LastModifiedTime, *) by IncidentNumber
| extend
    // MTTT / MTTH: Created -> FirstModified
    TTT_hours = iff(isnotnull(CreatedTime) and isnotnull(FirstModifiedTime),
                    datetime_diff("minute", FirstModifiedTime, CreatedTime) / 60.0,
                    real(null)),
    // MTTC: Created -> Closed
    TTC_hours = iff(isnotnull(CreatedTime) and isnotnull(ClosedTime),
                    datetime_diff("minute", ClosedTime, CreatedTime) / 60.0,
                    real(null)),
    // MTTD: FirstActivity -> Created
    TTD_hours = iff(isnotnull(FirstActivityTime) and isnotnull(CreatedTime),
                    datetime_diff("minute", CreatedTime, FirstActivityTime) / 60.0,
                    real(null))
| summarize
    ["MTTT/H (hours)"] = round(percentile(TTT_hours, 50), 2),
    ["MTTC (hours)"] = round(percentile(TTC_hours, 50), 2),
    ["MTTD (hours)"] = round(percentile(TTD_hours, 50), 2),
    ["MTTC, worst 10% (hours)"] = round(percentile(TTC_hours, 90), 2)
  by TimeBucket = bin(TimeGenerated, BinSize)
| sort by TimeBucket asc
| render timechart

// ---------------------------------------------
// Counts by Severity over time (TimeGenerated)
// Grouping controlled by workbook parameter {GroupBy}
// Options: ProductName, Tactics, Tags, Owner
// ---------------------------------------------
let BinSize  = 1d;
let StartTime = todatetime({TimeRange:start});
let EndTime   = todatetime({TimeRange:end});
let GroupBy = tostring("{GroupBy}");

SecurityIncident
| where TimeGenerated between (StartTime .. EndTime)

// ---- Your field extraction rules ----
| extend
    Product = tostring(parse_json(tostring(AdditionalData.alertProductNames))[0])
| extend
    Owner = todynamic(Owner.assignedTo)
| extend
    Tactics = todynamic(AdditionalData.tactics)
| extend
    Tags = extract_all('labelName":"(.*?)"', tostring(Labels))

// ---- Choose which list to expand (only for Tags/Tactics) ----
| extend
    ExpandArr = case(
        GroupBy == "Tactics", Tactics,
        GroupBy == "Tags", Tags,
        dynamic(["__NOEXPAND__"])
    )
| mv-expand ExpandArr to typeof(string)

// ---- Build the grouping key based on the parameter ----
| extend
    GroupKey = case(
        GroupBy == "ProductName", Product,
        GroupBy == "Owner", tostring(Owner),
        GroupBy in ("Tactics","Tags"), ExpandArr,
        "Unspecified"
    )
| extend
    GroupKey = iff(isempty(trim(" ", GroupKey)) or GroupKey == "__NOEXPAND__", "Unspecified", GroupKey)

// ---- Summarize by time + selected grouping ----
| summarize
    ["High 🔴"]          = countif(Severity == "High"),
    ["Medium 🟡"]        = countif(Severity == "Medium"),
    ["Low 🟢"]           = countif(Severity == "Low"),
    Informational        = countif(Severity == "Informational"),
    ["Count of Incidents"] = count(),
    IncidentNumbers      = array_sort_asc( make_set(IncidentNumber) )
  by TimeBucket = bin(TimeGenerated, BinSize), GroupKey

| sort by TimeBucket asc

//
// Forecast daily distinct incident volume
// - Look back 90 days (history window)
// - Forecast next 90 days
//
let LookbackDays = 90d;
let Step = 1d;
let ForecastDays = 90;                  // number of steps forward (must match Step)
let EndDate = now();
let StartDate = EndDate - LookbackDays; // explicit history window
let ProjectTo = EndDate + LookbackDays; // forecast horizon (90d forward)

SecurityIncident
// Use the same time column consistently (TimeGenerated is OK for volume; CreatedTime is also common)
| make-series IncidentCount = dcount(IncidentNumber) default=0
    on TimeGenerated
    from StartDate to ProjectTo step Step
// Forecast: returns a dynamic object; keep the original series too
| extend Forecast = series_decompose_forecast(IncidentCount, ForecastDays)

let lookback = 30d;

// =====================
// Office workloads (single scan)
// =====================
let Office =
    OfficeActivity
    | where TimeGenerated >= ago(lookback)
    | where OfficeWorkload in ("SharePoint", "Exchange", "MicrosoftTeams", "OneDrive")
    | extend Table = case(
        OfficeWorkload == "MicrosoftTeams", "Teams",
        OfficeWorkload
    )
    | summarize Count=count(), GB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 2) by Table;

let OfficeAll =
    datatable(Table:string)
    [
      "SharePoint",
      "Exchange",
      "Teams",
      "OneDrive"
    ]
    | join kind=leftouter Office on Table
    | extend Count = coalesce(Count, 0)
    | extend GB = coalesce(GB, 0.0)
    | extend Enabled = Count > 0
    | extend Section = "Office"
    | project Section, Table, Enabled, Count, GB;


// =====================
// Azure Activity (single scan)
// =====================
let AzureAll =
    AzureActivity
    | where TimeGenerated >= ago(lookback)
    | summarize Count=count(), GB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 2)
    | extend Table="AzureActivity"
    | extend Enabled = Count > 0
    | extend Section = "Azure"
    | project Section, Table, Enabled, Count, GB;


// =====================
// Defender Alerts (single scan)
// =====================
let Alerts =
    SecurityAlert
    | where TimeGenerated >= ago(lookback)
    | extend Table = case(
        ProviderName has "Azure Security Center", "Defender for Cloud Alerts",
        ProviderName has "MCAS", "Defender for Cloud Apps Alerts",
        ProviderName has "MDATP", "Defender for Endpoint Alerts",
        ProviderName has "OATP", "Defender for Office Alerts",
        ProviderName has "Azure Advanced Threat Protection", "Defender for Identity Alerts",
        ""
    )
    | where Table != ""
    | summarize Count=count(), GB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 2) by Table;

let AlertsAll =
    datatable(Table:string)
    [
      "Defender for Cloud Alerts",
      "Defender for Cloud Apps Alerts",
      "Defender for Endpoint Alerts",
      "Defender for Office Alerts",
      "Defender for Identity Alerts"
    ]
    | join kind=leftouter Alerts on Table
    | extend Count = coalesce(Count, 0)
    | extend GB = coalesce(GB, 0.0)
    | extend Enabled = Count > 0
    | extend Section = "Defender"
    | project Section, Table, Enabled, Count, GB;


// =====================
// Final: Section Health Summary
// =====================
OfficeAll
| union AzureAll, AlertsAll
| summarize
    EnabledTables = sum(toint(Enabled)),
    TotalTables   = count(),
    ['Ingested (GB)']       = round(sum(GB), 2),
    EnabledList   = make_set_if(Table, Enabled == true),
    MissingList   = make_set_if(Table, Enabled == false)
  by Section
| extend
    Status = strcat(EnabledTables, " / ", TotalTables),
    PercentEnabled = round(100.0 * EnabledTables / TotalTables, 1),
    EnabledList = strcat_array(EnabledList, ", "),
    MissingList = strcat_array(MissingList, ", ")
| order by Section asc
//| project-away EnabledList, MissingList

let lookback = 30d;

// Workbook parameters (defaults if empty) - TEXT parameters
let EntraAAD_P = iff(isempty(trim(" ", "{EntraAAD}")), 1, toint("{EntraAAD}"));
let Infra_P    = iff(isempty(trim(" ", "{Infra}")),    2, toint("{Infra}"));
let CSL_P      = iff(isempty(trim(" ", "{CSL}")),      2, toint("{CSL}"));
let MDE_P      = iff(isempty(trim(" ", "{MDE}")),      3, toint("{MDE}"));
let MDO_P      = iff(isempty(trim(" ", "{MDO}")),      3, toint("{MDO}"));
let MDI_P      = iff(isempty(trim(" ", "{MDI}")),      3, toint("{MDI}"));
let Other_P    = iff(isempty(trim(" ", "{Other}")),    4, toint("{Other}"));

// Section importance controls (defaults + overrides)
let SectionWeights =
    union
    (print Section="Entra/AAD", Importance=EntraAAD_P),
    (print Section="Infra",     Importance=Infra_P),
    (print Section="CSL",       Importance=CSL_P),
    (print Section="MDE",       Importance=MDE_P),
    (print Section="MDO",       Importance=MDO_P),
    (print Section="MDI",       Importance=MDI_P),
    (print Section="Other",     Importance=Other_P);

// =====================
// Entra / AAD (each table scanned once)
// =====================
let AADEnabled =
    union
    (SigninLogs                      | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="SigninLogs"),
    (AuditLogs                       | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="AuditLogs"),
    (AADNonInteractiveUserSignInLogs | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="AADNonInteractive"),
    (AADServicePrincipalSignInLogs   | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="Service Principal Sign-in"),
    (AADServicePrincipalRiskEvents   | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="Service Principal Risk Events"),
    (AADProvisioningLogs             | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="Provisioning logs"),
    (AADManagedIdentitySignInLogs    | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="Managed Identity logs"),
    (ADFSSignInLogs                  | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="ADFS Sign-ins"),
    (AADUserRiskEvents               | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="User Risk Events"),
    (AADRiskyUsers                   | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="Risky User Events")
    | project Table, c, IngestedGB;

let AADAll =
    datatable(Table:string)
    [
      "SigninLogs",
      "AuditLogs",
      "AADNonInteractive",
      "Service Principal Sign-in",
      "Service Principal Risk Events",
      "Provisioning logs",
      "Managed Identity logs",
      "ADFS Sign-ins",
      "User Risk Events",
      "Risky User Events"
    ]
    | join kind=leftouter AADEnabled on Table
    | extend Enabled = coalesce(c, 0) > 0
    | extend IngestedGB = coalesce(IngestedGB, 0.0)
    | extend Section = "Entra/AAD"
    | project Section, Table, Enabled, IngestedGB;

// =====================
// Infra (each table scanned once)
// =====================
let InfraEnabled =
    union
    (SecurityEvent | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="Windows Security Events"),
    (WindowsEvent  | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="Windows Events"),
    (Syslog        | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="Syslog")
    | project Table, c, IngestedGB;

let InfraAll =
    datatable(Table:string)
    [
      "Windows Security Events",
      "Windows Events",
      "Syslog"
    ]
    | join kind=leftouter InfraEnabled on Table
    | extend Enabled = coalesce(c, 0) > 0
    | extend IngestedGB = coalesce(IngestedGB, 0.0)
    | extend Section = "Infra"
    | project Section, Table, Enabled, IngestedGB;

// =====================
// CSL vendors (single scan of CommonSecurityLog)
// =====================
let CSLVendorsEnabled =
    CommonSecurityLog
    | where TimeGenerated >= ago(lookback)
    | extend Table = case(
        DeviceVendor has "Cisco", "Cisco",
        DeviceVendor has "Check Point", "Check Point",
        DeviceVendor has "Palo Alto", "Palo Alto",
        DeviceVendor has "F5", "F5",
        DeviceVendor has "Fortinet", "Fortinet",
        DeviceVendor has "Barracuda", "Barracuda",
        DeviceVendor has "ExtraHop", "ExtraHop",
        DeviceVendor has "OneIdentity", "OneIdentity",
        DeviceVendor has "Zscaler", "Zscaler",
        DeviceVendor has "ForgeRock", "ForgeRock",
        DeviceVendor has "CyberArk", "CyberArk",
        DeviceVendor has "Illusive", "Illusive",
        DeviceVendor has "Vectra Networks", "Vectra Networks",
        DeviceVendor has "Citrix", "Citrix",
        ""
    )
    | where Table != ""
    | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) by Table;

let CSLAll =
    datatable(Table:string)
    [
      "Cisco",
      "Check Point",
      "Palo Alto",
      "F5",
      "Fortinet",
      "Barracuda",
      "ExtraHop",
      "OneIdentity",
      "Zscaler",
      "ForgeRock",
      "CyberArk",
      "Illusive",
      "Vectra Networks",
      "Citrix"
    ]
    | join kind=leftouter CSLVendorsEnabled on Table
    | extend Enabled = coalesce(c, 0) > 0
    | extend IngestedGB = coalesce(IngestedGB, 0.0)
    | extend Section = "CSL"
    | project Section, Table, Enabled, IngestedGB;

// =====================
// MDE (each table scanned once)
// =====================
let MDEEnabled =
    union
    (DeviceInfo                | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDE Device Info"),
    (DeviceNetworkInfo         | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDE Device Network Info"),
    (DeviceProcessEvents       | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDE Device Process Events"),
    (DeviceNetworkEvents       | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDE Device Network Events"),
    (DeviceFileEvents          | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDE Device File Events"),
    (DeviceRegistryEvents      | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDE Device Registry Events"),
    (DeviceLogonEvents         | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDE Device Logon Events"),
    (DeviceImageLoadEvents     | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDE Device Image Load Events"),
    (DeviceEvents              | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDE Device Events"),
    (DeviceFileCertificateInfo | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDE Device File Certificate Info")
    | project Table, c, IngestedGB;

let MDEAll =
    datatable(Table:string)
    [
      "MDE Device Info",
      "MDE Device Network Info",
      "MDE Device Process Events",
      "MDE Device Network Events",
      "MDE Device File Events",
      "MDE Device Registry Events",
      "MDE Device Logon Events",
      "MDE Device Image Load Events",
      "MDE Device Events",
      "MDE Device File Certificate Info"
    ]
    | join kind=leftouter MDEEnabled on Table
    | extend Enabled = coalesce(c, 0) > 0
    | extend IngestedGB = coalesce(IngestedGB, 0.0)
    | extend Section = "MDE"
    | project Section, Table, Enabled, IngestedGB;

// =====================
// MDO (each table scanned once)
// =====================
let MDOEnabled =
    union
    (EmailEvents             | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDO Email Events"),
    (EmailUrlInfo            | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDO Email URL Info"),
    (EmailAttachmentInfo     | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDO Email Attachment Info"),
    (EmailPostDeliveryEvents | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDO Email Post-Delivery Events")
    | project Table, c, IngestedGB;

let MDOAll =
    datatable(Table:string)
    [
      "MDO Email Events",
      "MDO Email URL Info",
      "MDO Email Attachment Info",
      "MDO Email Post-Delivery Events"
    ]
    | join kind=leftouter MDOEnabled on Table
    | extend Enabled = coalesce(c, 0) > 0
    | extend IngestedGB = coalesce(IngestedGB, 0.0)
    | extend Section = "MDO"
    | project Section, Table, Enabled, IngestedGB;

// =====================
// MDI (own section; each table scanned once)
// =====================
let MDIEnabled =
    union
    (IdentityLogonEvents     | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDI Logon Events"),
    (IdentityQueryEvents     | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDI Query Events"),
    (IdentityDirectoryEvents | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDI Directory Events")
    | project Table, c, IngestedGB;

let MDIAll =
    datatable(Table:string)
    [
      "MDI Logon Events",
      "MDI Query Events",
      "MDI Directory Events"
    ]
    | join kind=leftouter MDIEnabled on Table
    | extend Enabled = coalesce(c, 0) > 0
    | extend IngestedGB = coalesce(IngestedGB, 0.0)
    | extend Section = "MDI"
    | project Section, Table, Enabled, IngestedGB;

// =====================
// Other (MDCA / TI; each table scanned once)
// =====================
let OtherEnabled =
    union
    (CloudAppEvents              | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="MDCA Cloud App Events"),
    (ThreatIntelligenceIndicator | where TimeGenerated >= ago(lookback) | summarize c=count(), IngestedGB=round(sum(_BilledSize) / 1024.0 / 1024.0 / 1024.0, 4) | extend Table="ThreatIntelligenceIndicator")
    | project Table, c, IngestedGB;

let OtherAll =
    datatable(Table:string)
    [
      "MDCA Cloud App Events",
      "ThreatIntelligenceIndicator"
    ]
    | join kind=leftouter OtherEnabled on Table
    | extend Enabled = coalesce(c, 0) > 0
    | extend IngestedGB = coalesce(IngestedGB, 0.0)
    | extend Section = "Other"
    | project Section, Table, Enabled, IngestedGB;

// =====================
// Final: Total Possible vs Enabled per Section (Workbook Tiles-ready)
// =====================
let AllSections =
    AADAll
    | union InfraAll, CSLAll, MDEAll, MDOAll, MDIAll, OtherAll
    | join kind=leftouter SectionWeights on Section;

AllSections
| summarize
    EnabledTables = sum(toint(Enabled)),
    TotalTables   = count(),
    IngestedGB    = round(sum(IngestedGB), 2)
  by Section, Importance
| extend
    Status = strcat(EnabledTables, " / ", TotalTables),
    PercentEnabled = round(100.0 * EnabledTables / TotalTables, 1)
| order by Importance asc, Section asc

// Thresholds
let stale_days = 30;
let aging_days = 14;

// Pull the watchlist
let WL = _GetWatchlist('{exportWatchlistAlias}');

// Watchlist stats
WL
| summarize
    NumberOfLines = count(),
    FirstItemAdded = min(LastUpdatedTimeUTC),
    LastItemAdded = max(LastUpdatedTimeUTC)
| extend
    DaysSinceUpdate = datetime_diff('day', now(), LastItemAdded)
| extend
    RecentlyUpdated = iif(DaysSinceUpdate <= 7 and DaysSinceUpdate >= 0, "Yes", "No"),
    HealthStatus = case(
        NumberOfLines == 0,               "Empty",
        DaysSinceUpdate > stale_days,     "Stale",
        DaysSinceUpdate > aging_days,     "Aging",
        DaysSinceUpdate < 0,              "FutureDate?",
                                         "Healthy"
    )

ThreatIntelIndicators
| where IsDeleted == false
| extend IndicatorType = case(
    // IPs (ipv4 + common network-traffic src/dst)
    ObservableKey in ('ipv4-addr:value','ipv6-addr:value',
                      'network-traffic:src_ref.value','network-traffic:dst_ref.value'), "IP",

    // URL
    ObservableKey == 'url:value', "URL",

    // Email address (new schema uses email-addr:value)
    ObservableKey == 'email-addr:value', "Email",

    // File hash
    ObservableKey has 'file:hashes', "File",

    // Domain
    ObservableKey == 'domain-name:value', "Domain",

    // Catch-all (includes rows where the pattern couldn’t be parsed into key/value)
    "Other"
)
| summarize CountOfIndicators = count() by IndicatorType, TimeBucket = bin(TimeGenerated, {TimeRange:grain})
| order by CountOfIndicators desc

