let lookback_days = 3;
// Build daily GB by table, excluding partial today
let daily =
   Usage
   | where TimeGenerated between (startofday(ago(lookback_days * 1d)) .. startofday(now()))
   | where IsBillable == true
   | summarize GB = sum(Quantity) / 1024.0  // MB -> GB
       by day = bin(TimeGenerated, 1d), Table = DataType;
// Split yesterday (D-1) and the day before (D-2)
