   | where day == startofday(ago(1d))
   | project Table, GB_Y = GB;
let d2 = daily
   | where day == startofday(ago(2d))
   | project Table, GB_D2 = GB;
// Compare and rank drops
y
| join kind=fullouter d2 on Table
| extend GB_D1  = round(coalesce(GB_Y,  0.0), 3),
         GB_D2  = round(coalesce(GB_D2, 0.0), 3)
| extend AbsDropGB = round(GB_D2 - GB_D1, 3),
         PctDrop   = round(100.0 * iif(GB_D2 == 0, 0.0, (GB_D2 - GB_Y) / GB_D2), 2)
| where AbsDropGB > 0 and isnotempty(Table) 
| order by AbsDropGB desc
| project Table, PercentageDrop = PctDrop ,Yesterday = GB_D2, Today=GB_D1, GBdrop = AbsDropGB

