SecurityIncident
//| summarize IncidentCount=count() by  Title, bin(TimeGenerated,1d)
| make-series IncidentCount=count() default=0 on TimeGenerated from {TimeRange:start} to projectTo step 1d 
| extend IncidentCountForecast = series_decompose_forecast(IncidentCount, projectForward)

// 1) Weekday-aware baseline (Mon vs Mon, Tue vs Tue)
// 2) Rolling 30-day median (responsive) and 90-day median (stable reference)
// 3) Dynamic threshold using stdev (flags statistically significant drops, not just % drops)
// 4) Connector health score (0–100)
// 5) Ignore tiny tables (minimum baseline GB/day)


let lookback = 90d;
let minBaselineGB = 0.10;          // ignore tiny tables (0.1 GB/day)
let pctDropTrigger = 50.0;         // classic % drop
let sigmaTrigger = 2.0;            // dynamic threshold: >=2σ drop
let todayWindow = 1d;              // last 24h

// 1) Daily ingestion per table (GB/day) + weekday
let daily =
Usage
| where TimeGenerated >= ago(lookback)
| where DataType !endswith "_RST" and DataType !endswith "_SRCH"
| summarize GB = sum(Quantity) / 1024.0 by DataType, Day = bin(TimeGenerated, 1d)
| extend Weekday = dayofweek(Day);

// "Today" bucket (last 24h) projected onto today's weekday
let today =
daily
| where Day >= ago(todayWindow)
| summarize TodayGB = sum(GB), TodayDay = max(Day) by DataType
| extend Weekday = dayofweek(TodayDay);

// 2) Weekday-aware rolling baselines (median) + 3) stdev for dynamic thresholds
let baseline30 =
daily
| where Day between (ago(30d) .. ago(1d))        // exclude last 24h to avoid contamination
| summarize
    BaselineGB_30 = percentile(GB, 50),
    StdevGB_30    = stdev(GB),
    Samples_30    = count()
  by DataType, Weekday;

let baseline90 =
daily
| where Day between (ago(90d) .. ago(1d))
| summarize
    BaselineGB_90 = percentile(GB, 50),
    StdevGB_90    = stdev(GB),
    Samples_90    = count()
  by DataType, Weekday;

today
| join kind=leftouter baseline30 on DataType, Weekday
| join kind=leftouter baseline90 on DataType, Weekday

// Prefer 30d median (more responsive). Fall back to 90d if 30d is missing.
| extend BaselineGB = coalesce(BaselineGB_30, BaselineGB_90),
         StdevGB    = coalesce(StdevGB_30,    StdevGB_90),
         Samples    = coalesce(Samples_30,    Samples_90)

// 5) prevent noise from small tables
| where isnotnull(BaselineGB) and BaselineGB >= minBaselineGB

// Drop metrics
| extend DropGB  = BaselineGB - TodayGB
| extend DropPct = iff(BaselineGB > 0, round(DropGB * 100.0 / BaselineGB, 2), real(null))
| extend ZDrop   = iff(StdevGB > 0, round(DropGB / StdevGB, 2), real(null))   // how many σ below baseline

// 4) Health / status (uses BOTH % and σ so it's stable)
| extend Status = case(
    TodayGB <= 0, "Dead",
    (DropPct >= pctDropTrigger and ZDrop >= sigmaTrigger), "Degraded",
    (DropPct >= 25.0 and ZDrop >= 1.0), "Warning",
    "Healthy"
)

// 4) Simple 0–100 health score (penalize big % drops + big σ drops)
| extend HealthScore =
    toint(
        max_of(
            0.0,
            100.0
            - min_of(80.0, max_of(0.0, DropPct))            // % drop penalty (capped)
            - min_of(20.0, max_of(0.0, (ZDrop - 1.0) * 10)) // σ penalty after 1σ
        )
    )

| where "All" in ({selectHealth})  or Status !in ({selectHealth})

| project
    DataType,
    Status,
    HealthScore,
    DropPct,
    DropGB = round(DropGB, 2),
    TodayGB = round(TodayGB, 2),
    BaselineGB = round(BaselineGB, 2),
    BaselineGB_30 = round(BaselineGB_30, 2),
    BaselineGB_90 = round(BaselineGB_90, 2)
    
    
   // ZDrop,
   // Samples_30,
   // Samples_90
| order by Status desc, HealthScore asc, DropPct desc

